<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div id="ReturnRequestHeading" class=" mt-2 theme-primary partition  p-actions-expand">
            <span class="p-name text-white"> {{ $t('Manage Taxes') }} </span>
        </div>
        <div class="border p-3">
            <dynamic-form lang="en" :schema="FormSchema"></dynamic-form>
        </div>
        <AddItemPopup v-if="AddItem"></AddItemPopup>
        <Form ref="form">
            <div class="col-lg-12">
                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left p-0 mb-2"
                    v-for="(taxDataitem, taxDataIndex) in taxData">
                    <div class="black-header ">
                        <div class="">
                            <div class="col-lg-12 mt-3 p-0" v-if="taxDataitem.forName == 'country'">
                                <div class="heading-border mb-2">
                                    <h5 class="h5">
                                        <span>{{ $t('CountryTax') }}</span><small class="float-right">
                                            <a v-if="taxDataitem.forName == 'country'"
                                                v-on:click="AddMoreTax('0', taxDataIndex)">
                                                <i class="fa fa-plus pr-2"></i>{{ $t('AddNew') }}
                                            </a>
                                        </small>
                                    </h5>
                                </div>
                            </div>
                            <div class="col-lg-12 mt-3 p-0" v-if="taxDataitem.forName == 'state'">
                                <div class="heading-border mb-2">
                                    <h5 class="h5">
                                        <span>{{ $t('StateTax') }}</span><small class="float-right">
                                            <a href="javascript:;" v-if="taxDataitem.forName == 'state'"
                                                v-on:click="AddMoreTax('1', taxDataIndex)">
                                                <i class="fa fa-plus pr-2"></i>{{ $t('AddNew') }}
                                            </a>
                                        </small>
                                    </h5>
                                </div>
                            </div>
                            <div class="col-lg-12 mt-3 p-0" v-if="taxDataitem.forName == 'district'">
                                <div class="heading-border mb-2">
                                    <h5 class="h5">
                                        <span>{{ $t('CountyTax') }}</span><small class="float-right">
                                            <a href="javascript:;" v-if="taxDataitem.forName == 'district'"
                                                v-on:click="AddMoreTax('2', taxDataIndex)">
                                                <i class="fa fa-plus pr-2"></i>{{ $t('AddNew') }}
                                            </a>
                                        </small>
                                    </h5>
                                </div>
                            </div>
                            <div class="col-lg-12 mt-3 p-0" v-if="taxDataitem.forName == 'zipcode'">
                                <div class="heading-border mb-2">
                                    <h5 class="h5">
                                        <span>{{ $t('ZipcodeTax') }}</span><small class="float-right">
                                            <a href="javascript:;" v-if="taxDataitem.forName == 'zipcode'"
                                                v-on:click="AddMoreTax('3', taxDataIndex)">
                                                <i class="fa fa-plus pr-2"></i>{{ $t('AddNew') }}
                                            </a>
                                        </small>
                                    </h5>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="col-12 float-left p-0 py-2 mb-2 highlighter">
                        <div class="col-12 float-left mt-2 p-0 bg_highlighter"
                            v-for="(txtforItem, txtforIndex) in taxDataitem.taxFor"
                            v-if="txtforItem.taxItem[0].is_deleted == 0">
                            <div class="row">
                                <div class="col-11 p-0 d-flex flex-wrap">
                                    <div class="dropdown-container col-lg-4">
                                        <multiselect placeholder="Select Country" :max-height="150"
                                            v-model="txtforItem.countryId" label="name" track-by="value" :limit="2"
                                            :options="CountryData" :multiple="false" :taggable="true"
                                            @input="setSelectedValue(txtforItem, $event, taxDataIndex, txtforIndex, '')">
                                        </multiselect>
                                    </div>
                                    <div class="dropdown-container col-lg-4" v-if="txtforItem.taxForName == 'state'">
                                        <Field :name="'State'" v-slot="{ errors }"
                                            :rules="taxTypeRules(txtforItem.countryId.value)">
                                            <multiselect placeholder="Select State" :max-height="150"
                                                v-model="txtforItem.stateId" label="name" track-by="value" :limit="2"
                                                :options="txtforItem.taxForOption" :multiple="true" :taggable="true">
                                            </multiselect>
                                            <span v-if="errors[0]" :name="'State'" class="invalid-feedback d-block">{{
                                                errors[0] }}</span>
                                        </Field>
                                    </div>
                                    <div class="dropdown-container col-lg-4" v-if="txtforItem.taxForName == 'district'">
                                        <Field :name="'District'" v-slot="{ errors }"
                                            :rules="taxTypeRules(txtforItem.countryId.value)">
                                            <multiselect placeholder="Select District" :max-height="150"
                                                v-model="txtforItem.districtId" label="name" track-by="value" :limit="2"
                                                :options="txtforItem.taxForOption" :multiple="true" :taggable="true">
                                            </multiselect>
                                            <span v-if="errors[0]" :name="'District'"
                                                class="invalid-feedback d-block">{{ errors[0] }}</span>
                                        </Field>
                                    </div>
                                    <div class="dropdown-container col-lg-4" v-if="txtforItem.taxForName == 'zipcode'">
                                        <Field :name="'Zipcode'" v-slot="{ errors }"
                                            :rules="taxTypeRules(txtforItem.countryId.value)">
                                            <multiselect placeholder="Select zipcode" :max-height="150"
                                                v-model="txtforItem.zipCodeId" label="name" track-by="value" :limit="2"
                                                :options="txtforItem.taxForOption" :multiple="true" :taggable="true">
                                            </multiselect>
                                            <span v-if="errors[0]" :name="'Zipcode'" class="invalid-feedback d-block">{{
                                                errors[0] }}</span>
                                        </Field>
                                    </div>
                                    <div class="col-4 float-right">
                                        <a href="javascript:;" class="btn formbtn "
                                            v-on:click="RemoveTaxForRow(txtforItem, taxDataIndex, txtforIndex)"
                                            v-if="txtforIndex > 0">
                                            <i class="fa fa-trash text-danger" style="font-size:23px;"></i>
                                            <span class="ml-1 text-dark" style="font-size:14px;"></span>
                                        </a>
                                    </div>
                                </div>
                            </div>
                            <div class="row mt-2">
                                <div class="input-group divfield float-left"
                                    v-for="(taxitem, taxItemIndex) in txtforItem.taxItem"
                                    v-if="taxitem.is_deleted == 0">
                                    <div class="col-11 float-left p-0">
                                        <div class="col-sm-12 col-md-4 col-lg-4 col-xl-4 float-left">
                                            <Field :name="'taxName' + taxDataIndex + txtforIndex + taxItemIndex"
                                                v-slot="{ errors }" :rules="taxTypeRules(txtforItem.countryId.value)">
                                                <input class="form-control"
                                                    v-bind:name="'taxName' + taxDataIndex + txtforIndex + taxItemIndex"
                                                    v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                    v-model.trim="taxitem.taxName" placeholder="Enter Name" />
                                                <span v-if="errors[0]" class="invalid-feedback d-block">Tax Name is
                                                    required</span>
                                            </Field>
                                        </div>
                                        <div class="col-sm-12 col-md-4 col-lg-4 col-xl-4 float-left">
                                            <Field :name="'taxType' + taxDataIndex + txtforIndex + taxItemIndex"
                                                v-slot="{ errors }" :rules="taxTypeRules(txtforItem.countryId.value)">
                                                <select class="form-control"
                                                    v-bind:name="'taxType' + taxDataIndex + txtforIndex + taxItemIndex"
                                                    v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                    v-model="taxitem.taxType">
                                                    <option value="">{{ $t('SelectTaxType') }}</option>
                                                    <option value="percent">{{ $t('Percent') }}</option>
                                                    <option value="flat">{{ $t('Flat') }}</option>
                                                </select>
                                                <span v-if="errors[0]" class="invalid-feedback d-block">Tax type is
                                                    required</span>
                                            </Field>
                                        </div>
                                        <div class="col-sm-12 col-md-4 col-lg-4 col-xl-4 float-left">
                                            <Field :name="'taxValue' + taxDataIndex + txtforIndex + taxItemIndex"
                                                v-slot="{ errors }" :rules="taxTypeRules(txtforItem.countryId.value)">
                                                <input v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                    v-model.number="taxitem.taxValue"
                                                    :name="'taxValue' + taxDataIndex + txtforIndex + taxItemIndex"
                                                    v-on:keypress="isNumber($event)"
                                                    v-on:keyup="CheckProbability(taxitem)" placeholder="Enter Value" />
                                                <span v-if="errors[0]" class="invalid-feedback d-block">Tax is
                                                    required</span>
                                            </Field>
                                        </div>
                                    </div>
                                    <div class="col-1 float-left">
                                        <a href="javascript:;" class="btn formbtn"
                                            v-on:click="RemoveTaxRow(taxitem, taxItemIndex, taxDataIndex, txtforIndex)"
                                            title="Delete Line Item" v-if="taxItemIndex > 0">
                                            <i class="fa fa-trash text-danger" style="font-size:23px;"></i>
                                        </a>
                                        <a href="javascript:;" class="btn formbtn text-success"
                                            title="Add More Line Item"
                                            v-on:click="AddNewItem(taxDataIndex, txtforIndex)" v-if="taxItemIndex == 0">
                                            <i class="fa fa-plus text-success" style="font-size:23px;"></i>
                                        </a>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
                <div class="col-12 float-right text-right py-1">
                    <a href="javascript:;" title="Save" v-if="taxItemCodeId > 0" class="btn btn-success"
                        v-on:click="SaveTax()"><i class="fa fa-save pr-2"></i> Save</a>
                </div>
            </div>
        </Form>
    </section>
</template>
<script>
import DataServices from "@/services/DataService";
import AddItemPopup from './AddItemCodeModel.vue'
export default {
    components: { AddItemPopup },
    props: {
    },
    data() {
        return {
            isLoading: false,
            AddItem: false,
            isLoading: false,
            searchQuery: '',
            selectedCountry: null,
            filteredOptions: [],
            taxItemCodeId: 0,
            user_id: null,
            companyId: null,
            taxData: [],
            CountryData: [],
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "CustomSelectField",
                            name: "ItemCode",
                            value: "",
                            config: {
                                options: [],
                                onSearchChange: this.onSearch,
                                onChange: this.onChangeItemCode,
                                showAddIcon: true,
                                onAddButtonClick: this.AddItemCode,
                            },
                            placeholder: this.$t('Select Item Code'),
                            validationRules: {
                                "required": false
                            },
                        },
                    ],
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.user_id = this.GetUserInfo.ID;
        vm.companyId = this.GetUserInfo.CompanyId;
        await vm.ShowSearchData("", "COUNTRIES");
        await vm.ShowSearchData("", "TAX_CODE");
    },
    methods: {
        AddItemCode() {
            var vm = this;
            vm.AddItem = !vm.AddItem;
        },
        taxTypeRules(Id) {
            var vm = this;
            if (Id > 0) {
                return {
                    required: true
                };
            }
            return {
                required: false
            };
        },
        isNumber: function (evt) {
            evt = (evt) ? evt : window.event;
            var charCode = (evt.which) ? evt.which : evt.keyCode;
            if ((charCode > 31 && (charCode < 48 || charCode > 57)) && charCode !== 46) {
                evt.preventDefault();;
            } else {
                return true;
            }
        },
        setSelectedValue(item, selectedValue, taxDataIndex, txtforIndex, extraParam) {
            var vm = this;
            var isFor = 'search';
            var type = item.taxForName;
            var val = selectedValue.value;
            var appendingUrl = `id=&moduleName=${'CRM'}&type=${type}&search=${extraParam}&refId=${val}`;
            DataServices.getDDLData(appendingUrl).then(function (response) {
                if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        if (isFor == 'search') {
                            item.taxForOption = json.DATA;  
                            item.stateId = []; 
                            item.districtId = [];
                            item.zipCodeId = [];
                        }
                        else {
                            this.taxData[taxDataIndex].taxFor[taxForIndex].taxForOption = json.DATA;
                            if (isFor != 'search') {
                                this.taxData[taxDataIndex].taxFor[taxForIndex].countryId = val;
                            }
                        }
                    } else {
                        this.taxData[taxDataIndex].taxFor[taxForIndex].taxForOption = [];
                        if (isFor != 'search') {
                            this.taxData[taxDataIndex].taxFor[taxForIndex].countryId = val;
                        }
                    }
                }
            });
        },
        AddMoreTax: function (type, taxDataIndex) {
            var vm = this;
            var taxForArray = [
                { name: "country" },
                { name: "state" },
                { name: "district" },
                { name: "zipcode" }];
            var taxItem = [{ taxName: "", taxType: "", taxValue: "", is_now_created: 1, taxId: "0", is_deleted: 0 }];
            var taxFor = { taxForName: taxForArray[type].name, countryId: '', stateId: '', districtId: '', zipCodeId: '', taxForOption: [], taxItem: taxItem, is_now_created: 1, is_deleted: 0 };
            vm.taxData[taxDataIndex].taxFor.push(taxFor);
        },
        AddNewItem: function (taxDataIndex, taxForIndex) {
            var vm = this;
            var taxItem = { taxName: "", taxType: "", taxValue: "", is_now_created: 1, taxId: "0", is_deleted: 0 };
            vm.taxData[taxDataIndex].taxFor[taxForIndex].taxItem.push(taxItem);
        },
        RemoveTaxRow: function (childItem, taxItemIndex, taxDataIndex, taxForIndex) {
            var vm = this;
            vm.confirmR(vm.$t("ConfirmDeleteField"), true, vm.$t('Remove'), function () {

                if (childItem.taxId > 0) {
                    childItem.is_deleted = 1;
                } else {
                    vm.taxData[taxDataIndex].taxFor[taxForIndex].taxItem.splice(taxItemIndex, 1);
                }
            }, function () {
            });
        },
        RemoveTaxForRow: function (item, taxDataIndex, taxForIndex) {
            var vm = this;
            vm.confirmR(vm.$t("ConfirmDeleteField"), true, vm.$t('Remove'), function () {
                var ifNotEditable = true;
                item.taxItem.forEach(function (taxItem, taxIndex) {
                    if (taxItem.taxId > 0) {
                        taxItem.is_deleted = 1;
                        ifNotEditable = false;
                    } else {
                        vm.taxData[taxDataIndex].taxFor[taxForIndex].taxItem.splice(taxIndex, 1);
                    }
                });
                if (ifNotEditable) {
                    vm.taxData[taxDataIndex].taxFor.splice(taxForIndex, 1);
                } else {
                    item.is_deleted = 1;
                }
            }, function () {
            });
        },
        onChangeItemCode: async function (e, x, y) {
            var vm = this;
            vm.isLoading = true;
            vm.taxData = [];
            vm.taxItemCodeId = y.value;

            var taxForArray = [
                { name: "country" },
                { name: "state" },
                { name: "district" },
                { name: "zipcode" }
            ];

            var appendingUrl = `id=${y.value}`;

            try {
                const response = await DataServices.GetTaxByCodeId(appendingUrl);

                if (response.data) {
                    vm.isLoading = false;

                    if (response.data != null) {
                        const fullData = response.data.DATA;
                        console.log(response.data.DATA);

                        if (fullData != null) {
                            for (const taxFor of taxForArray) {
                                const taxForName = taxFor.name;
                                const chkGroup = fullData.filter(element => element.TAX_FOR === taxForName);

                                if (chkGroup.length > 0) {
                                    const taxForItems = [];
                                    let chktaxFor = '';
                                    let chktaxItemGroup = '';

                                    for (const taxForItem of chkGroup) {
                                        let chktaxItem = [];
                                        let taxItems = [];

                                        if (taxForName === "country") {
                                            chktaxFor = taxForItem.TAX_COUNTRY;
                                            chktaxItem = fullData.filter(element => element.TAX_FOR === taxForName && element.TAX_COUNTRY === taxForItem.TAX_COUNTRY);
                                        } else if (taxForName === "state") {
                                            chktaxFor = taxForItem.TAX_STATE;
                                            chktaxItem = fullData.filter(element => element.TAX_FOR === taxForName && element.TAX_STATE === taxForItem.TAX_STATE);
                                        } else if (taxForName === "district") {
                                            chktaxFor = taxForItem.TAX_DISTRICT;
                                            chktaxItem = fullData.filter(element => element.TAX_FOR === taxForName && element.TAX_DISTRICT === taxForItem.TAX_DISTRICT);
                                        } else if (taxForName === "zipcode") {
                                            chktaxFor = taxForItem.TAX_ZIPCODE;
                                            chktaxItem = fullData.filter(element => element.TAX_FOR === taxForName && element.TAX_ZIPCODE === taxForItem.TAX_ZIPCODE);
                                        }

                                        if (chktaxItem.length > 0) {
                                            taxItems = [];

                                            if (chktaxFor !== chktaxItemGroup) {
                                                for (const taxItem of chktaxItem) {
                                                    const obj = {
                                                        taxName: taxItem.TAX_NAME,
                                                        taxId: taxItem.TAX_ID,
                                                        taxType: taxItem.TAX_TYPE,
                                                        taxValue: taxItem.TAX_RATE,
                                                        is_now_created: 0,
                                                        is_deleted: 0
                                                    };
                                                    taxItems.push(obj);
                                                }

                                                let taxForOptions = [];
                                                let countryOptions = [];
                                                let Options = [];

                                                if (chktaxItem[0].TAX_COUNTRY_OPTIONS !== '') {
                                                    countryOptions = vm.MakeNormalArray(chktaxItem[0].TAX_COUNTRY_OPTIONS);
                                                }

                                                if (chktaxItem[0].TAX_ZIPCODE_OPTIONS !== '' && taxForName === "zipcode") {
                                                    taxForOptions = vm.MakeNormalArray(chktaxItem[0].TAX_ZIPCODE_OPTIONS);
                                                    Options = await vm.GetDDlOptionBYCountryId(taxForItem, taxForItem.TAX_COUNTRY, '');
                                                } else if (chktaxItem[0].TAX_DISTRICT_OPTIONS !== '' && taxForName === "district") {
                                                    taxForOptions = vm.MakeNormalArray(chktaxItem[0].TAX_DISTRICT_OPTIONS);
                                                    Options = await vm.GetDDlOptionBYCountryId(taxForItem, taxForItem.TAX_COUNTRY, '');
                                                } else if (chktaxItem[0].TAX_STATE_OPTIONS !== '' && taxForName === "state") {
                                                    taxForOptions = vm.MakeNormalArray(chktaxItem[0].TAX_STATE_OPTIONS);
                                                    Options = await vm.GetDDlOptionBYCountryId(taxForItem, taxForItem.TAX_COUNTRY, '');
                                                }

                                                if (taxForOptions != null && taxForOptions.length > 0) {
                                                    const taxFor = {
                                                        taxForName: taxForName,
                                                        countryId: countryOptions[0],
                                                        stateId: taxForOptions,
                                                        districtId: taxForOptions,
                                                        zipCodeId: taxForOptions,
                                                        taxForOption: Options,
                                                        taxItem: taxItems,
                                                        is_deleted: 0
                                                    };
                                                    taxForItems.push(taxFor);
                                                } else {
                                                    const taxFor = {
                                                        taxForName: taxForName,
                                                        countryId: countryOptions[0],
                                                        stateId: chktaxItem[0].TAX_STATE,
                                                        districtId: chktaxItem[0].TAX_DISTRICT,
                                                        zipCodeId: chktaxItem[0].TAX_ZIPCODE,
                                                        taxForOption: taxForOptions,
                                                        taxItem: taxItems,
                                                        is_deleted: 0
                                                    };
                                                    taxForItems.push(taxFor);
                                                }
                                            }

                                            if (taxForName === "country") {
                                                chktaxItemGroup = chktaxItem[0].TAX_COUNTRY;
                                            } else if (taxForName === "state") {
                                                chktaxItemGroup = chktaxItem[0].TAX_STATE;
                                            } else if (taxForName === "district") {
                                                chktaxItemGroup = chktaxItem[0].TAX_DISTRICT;
                                            } else if (taxForName === "zipcode") {
                                                chktaxItemGroup = chktaxItem[0].TAX_ZIPCODE;
                                            }
                                        } else {
                                            taxItems = [{
                                                taxName: "",
                                                taxType: "",
                                                taxValue: "",
                                                taxId: "0",
                                                is_now_created: 0,
                                                is_deleted: 0
                                            }];
                                            const taxFor = {
                                                taxForName: taxForName,
                                                countryId: taxForItem.TAX_COUNTRY[0],
                                                stateId: taxForItem.TAX_STATE,
                                                districtId: taxForItem.TAX_DISTRICT,
                                                zipCodeId: taxForItem.TAX_ZIPCODE,
                                                taxForOption: [],
                                                taxItem: taxItems,
                                                is_deleted: 0
                                            };
                                            taxForItems.push(taxFor);
                                        }
                                    }

                                    const object = {
                                        forName: taxForName,
                                        taxFor: taxForItems,
                                    };
                                    vm.taxData.push(object);
                                } else {
                                    vm.RenderItem(taxForName);
                                }
                            }
                        } else {
                            vm.RenderEmptyData(taxForArray);
                        }
                    } else {
                        vm.RenderEmptyData(taxForArray);
                    }
                } else {
                    vm.isLoading = false;
                    vm.RenderEmptyData(taxForArray);
                }
            } catch (error) {
                console.error("Error fetching tax data:", error);
                vm.isLoading = false;
                vm.RenderEmptyData(taxForArray);
            }
        },

        async GetDDlOptionBYCountryId(item, selectedValue, extraParam) {
            var vm = this;
            var isFor = 'search';
            var type = item.TAX_FOR;
            var val = selectedValue;
            var appendingUrl = `id=&moduleName=${'CRM'}&type=${type}&search=${extraParam}&refId=${val}`;
            try {
                const response = await DataServices.getDDLData(appendingUrl);
                if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        if (isFor == 'search') {
                            return json.DATA;
                        } else {
                            vm.taxData[index].taxFor[index].taxForOption = json.DATA;
                            if (isFor != 'search') {
                                vm.taxData[index].taxFor[index].countryId = val;
                            }
                        }
                    } else {
                        vm.taxData[index].taxFor[index].taxForOption = [];
                        if (isFor != 'search') {
                            vm.taxData[index].taxFor[index].countryId = val;
                        }
                    }
                }
            } catch (error) {
                console.error("Error fetching DDL options: ", error);
                return [];
            }
        },

        MakeNormalArray: function (value) {
            if (value) {
                try {
                    return JSON.parse(value);
                }
                catch (ex) {
                    return value;
                }
            }
            else {
                value = [];
            }
        },

        RenderEmptyData: function (taxForArray) {
            var vm = this;
            for (var i = 0; i < taxForArray.length; i++) {
                vm.RenderItem(taxForArray[i].name);
            };
        },
        RenderItem: function (taxForName) {
            var vm = this;
            var taxItem = [{ taxName: "", taxType: "", taxValue: "", taxId: "0", is_now_created: 1, is_deleted: 0 }];
            var taxFor = [{
                taxForName: taxForName, countryId: '', stateId: '', districtId: '', zipCodeId: '', taxForOption: [], taxItem: taxItem, is_now_created: 1, is_deleted: 0
            }];
            var object = {
                forName: taxForName,
                taxFor: taxFor,
            };
            vm.taxData.push(object);
        },
        onSearch: async function (e, selctedValue, search) {
            var vm = this;
            this.searchSelectData(search, this, selctedValue);
        },
        searchSelectData: async function (search, selctedValue) {
            var vm = this;
            this.ShowSearchData(search, vm, selctedValue);
        },
        ShowSearchData: async function (search, selctedValue) {
            var vm = this;
            search != '' ? selctedValue = "TAX_CODE" : selctedValue;
            var appendingUrl = `id=&moduleName=${'CRM'}&type=${selctedValue}&search=${search}&refId=`;
            if (typeof (selctedValue) == 'undefined') {
                selctedValue = 0;
            }
            vm.FormSchema[0].Data[0].config.options = [];
            await DataServices.getDDLData(appendingUrl).then(function (response) {
                if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        if (selctedValue == 'TAX_CODE') {
                            response.data.DATA.forEach((item, index) => {
                                vm.FormSchema[0].Data[0].config.options.push({
                                    value: item.value,
                                    name: item.name
                                })
                            })
                        } else {
                            vm.CountryData = response.data.DATA;
                        }
                    }
                }
            });
        },
        SaveTax: function () {
            var vm = this;
            var postData = [];
            vm.$refs.form.validate().then(async result => {
                if (result) {
                    vm.taxData.forEach(function (taxDataItem) {
                        taxDataItem.taxFor.forEach(function (taxForItem) {
                            taxForItem.taxItem.forEach(function (taxItem) {
                                var countryId = taxForItem.countryId;
                                if (typeof taxForItem.countryId === 'object' && !Array.isArray(taxForItem.countryId)) {
                                    countryId = taxForItem.countryId.value;
                                }
                                else if (Array.isArray(taxForItem.countryId)) {
                                    countryId = vm.createString(taxForItem.countryId, 'value');
                                }

                                var stateId = taxForItem.stateId;
                                if (Array.isArray(taxForItem.stateId)) {
                                    stateId = vm.createString(taxForItem.stateId, 'value');
                                }

                                var districtId = taxForItem.districtId;
                                if (Array.isArray(taxForItem.districtId)) {
                                    districtId = vm.createString(taxForItem.districtId, 'value');
                                }

                                var zipCodeId = taxForItem.zipCodeId;
                                if (Array.isArray(taxForItem.zipCodeId)) {
                                    zipCodeId = vm.createString(taxForItem.zipCodeId, 'value');
                                }

                                if (countryId != '') {
                                    var obj = {
                                        id: taxItem.taxId,
                                        name: taxItem.taxName,
                                        taxFor: taxForItem.taxForName,
                                        countryId: countryId,
                                        stateId: taxForItem.taxForName == "state" ? stateId : '',
                                        districtId: taxForItem.taxForName == "district" ? districtId : '',
                                        zipCodeId: taxForItem.taxForName == "zipcode" ? zipCodeId : '',
                                        taxType: taxItem.taxType,
                                        taxValue: taxItem.taxValue,
                                        is_now_created: taxItem.is_now_created,
                                        is_deleted: taxItem.is_deleted
                                    };
                                    postData.push(obj);
                                }
                            });
                        });
                    });
                    var mainPostData = {
                        userId: vm.user_id,
                        companyId: vm.companyId,
                        CodeId: vm.taxItemCodeId,
                        taxData: postData
                    };
                    var params = JSON.stringify(mainPostData);
                    DataServices.SaveTaxByCode(params).then((response) => {
                        if (response.data[0].Status == 'Success') {
                            vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Tax")]), "success", true, vm.$t("Alert"));
                            vm.Close();
                        }
                        else {
                            vm.ShowAlert(vm.$t("AddedError", [vm.$t("Tax")]), "failure", true, vm.$t("Alert"));
                            vm.Close();
                        }
                    });
                }
            })
        }

    }
}
</script>
